}

/**
 * Finds all "good integers" less than or equal to n.
 * A good integer x is a number that can be expressed as a^3 + b^3 in at least two different ways,
 * where a and b are positive integers and a <= b.
 * 
 * @param n The upper limit.
 * @returns An array of good integers less than or equal to n, sorted in ascending order.
 */
function solve(n: number): number[] {
