    // Since a >= 1 and b >= a, the minimum value for a^3 + b^3 is 1^3 + 1^3 = 2.
    // The maximum value for b is such that b^3 <= n, so b <= cbrt(n).
    // Since n <= 10^9, cbrt(n) <= 1000.

    const maxB = Math.floor(Math.cbrt(n));

    // Map to store the sums found and how many ways they can be formed.
    // Key: sum (x), Value: count of distinct pairs (a, b) that result in x.
    const sumCounts = new Map<number, number>();

    // Iterate over possible values for 'a' (1 <= a)
    for (let a = 1; a * a * a <= n; a++) {
        // Iterate over possible values for 'b' (b >= a)
